import json
import os
import sys
from pathlib import Path

vendor_dir = Path("/tmp/vendor")
cache_dir = Path("/usr/local/cargo/registry/cache/index.crates.io-6f17d22bba15001f")

def file_sha256(p):
    h = hashlib.sha256()
    with open(p, "rb") as f:
        for chunk in iter(lambda: f.read(65536), b""):
            h.update(chunk)
    return h.hexdigest()

for crate_dir in sorted(vendor_dir.iterdir()):
