            files[rel] = file_sha256(full)
    out = {"files": files, "package": package_sha}
    with open(crate_dir / ".cargo-checksum.json", "w") as f:
        json.dump(out, f)
    print(f"wrote {crate_dir}/.cargo-checksum.json ({len(files)} files)")

