/* Standard Library */
use std::path::Path;

/* Internal Modules */
pub mod error;
use error::ScrawlError;

pub mod editor;

/* Convenience functions */
/// New opens an empty text buffer in an editor and returns a Result<String> with the contents.
///
/// # Example
/// ```no_run
/// # use scrawl::error::ScrawlError;
/// # fn main() -> Result<(), ScrawlError> {
///     let output = scrawl::new()?;
///     println!("{}", output);
/// #   Ok(())
/// # }
/// ```
pub fn new() -> Result<String, ScrawlError> {
    editor::new().open()
}

/// With opens a text buffer with the contents of the provided String in an editor. Returns a Result<String> with the edited contents.
///
/// # Example
/// ```no_run
/// # use scrawl::error::ScrawlError;
/// # fn main() -> Result<(), ScrawlError> {
///     let output = scrawl::with("Hello World!")?;
///     println!("{}", output);
/// #   Ok(())
/// # }
/// ```
pub fn with(content: &str) -> Result<String, ScrawlError> {
    editor::new().contents(content).open()
}

/// Open opens a text buffer in an editor with the contents of the file specified. This does **not** edit the contents of the file. Returns a Result<String> with the contents of the buffer.
///
/// # Example
/// ```no_run
/// # use scrawl::error::ScrawlError;
/// # use std::path::Path;
///
/// # fn main() -> Result<(), ScrawlError> {
///     let output = scrawl::open("hello.txt")?;
///     println!("{}", output);
///
///     let path = Path::new("website.html");
///     let output = scrawl::open(path)?;
///     println!("{}", output);
/// #   Ok(())
/// # }
/// ```
pub fn open<P: AsRef<Path>>(path: P) -> Result<String, ScrawlError> {
    editor::new().file(path.as_ref()).open()
}

/// Edit opens a text buffer in an editor with the contents of the file specified. This **does** edit the contents of the file. Returns a Result<String> with the contents of the buffer.
///
/// # Example
/// ```no_run
/// # use scrawl::error::ScrawlError;
/// # use std::path::Path;
///
/// # fn main() -> Result<(), ScrawlError> {
///     /* Directly edits the file, no output is returned */
///     scrawl::edit("hello.txt")
/// # }
/// ```
pub fn edit<P: AsRef<Path>>(path: P) -> Result<(), ScrawlError> {
    editor::new().file(path.as_ref()).edit().open()
}

//! # Scrawl Error Types
//! Error enum used by the Scrawl crate.
use std::error::Error;
use std::fmt;

/// Error enum for the Scrawl crate
#[derive(Debug)]
pub enum ScrawlError {
    /// Could not create a new temporary file to use as a buffer for Scrawl.
    FailedToCreateTempfile,
    /// Could not open the editor, or the editor quit with an error.
    FailedToOpenEditor(String),
    /// Could not read the file into a valid UTF-8 String.
    FailedToCaptureInput,
    /// Could not open the file specified in the scrawl::open function.
    FailedToCopyToTempFile(String),
}

/* Display and Debug are required to satisfy the Error trait. Debug has been
   derived for ScrawlError.
*/
impl fmt::Display for ScrawlError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        let error = match self {
            ScrawlError::FailedToCreateTempfile => String::from(
                "Could not \
                 create a temporary file to serve as a buffer for the editor.",
            ),

            ScrawlError::FailedToOpenEditor(editor) => format!(
                "Failed to \
                 open `{}` as a text editor or editor was terminated with errors.",
                editor
            ),

            ScrawlError::FailedToCaptureInput => String::from(
                "Failed to \
                 capture input. Was not a valid UTF-8 String.",
            ),

            ScrawlError::FailedToCopyToTempFile(filename) => format!(
                "Failed \
                 to copy the contents of the `{}` to the buffer for editing.",
                filename
            ),
        };

        write!(f, "{}", error)
    }
}

/* Cowards way out */
impl Error for ScrawlError {
    fn source(&self) -> Option<&(dyn Error + 'static)> {
        None
    }
}
