#[macro_use]
extern crate prettytable;
#[macro_use]
extern crate lazy_static;
#[macro_use]
extern crate serde_derive;

pub mod cli;
pub mod config;
pub mod defaults;
pub mod error;
pub mod script;

use std::io::Write;
use std::path::PathBuf;
use std::process::exit;

use prettytable::format::{FormatBuilder, LinePosition, LineSeparator, TableFormat};
use prettytable::Table;

use crate::cli::{AddOpts, Cli, CliSubcommand, ListOpts};
use crate::config::Config;
use crate::error::PierError;
use crate::script::Script;

lazy_static! {
    pub static ref COOL_FORMAT: TableFormat = FormatBuilder::new()
        .column_separator('\u{22EE}')
        .borders('\u{22EE}')
        .separators(
            &[LinePosition::Top, LinePosition::Title, LinePosition::Bottom],
            LineSeparator::new('\u{2256}', '\u{2256}', '\u{2256}', '\u{2256}')
        )
        .padding(1, 1)
        .build();
}

pub struct Pier {
    pub config: Config,
    pub path: PathBuf,
}

impl Pier {
    pub fn from(path: PathBuf) -> Result<Pier, PierError> {
        let config = Config::read(&path)?;
        Ok(Pier { config, path })
    }

    pub fn fetch_script(&self, alias: &str) -> Result<&Script, PierError> {
        if self.config.scripts.is_empty() {
            return Err(PierError::NoScriptsExist);
        }
        match self.config.scripts.get(alias) {
            Some(s) => Ok(s),
            None => Err(PierError::AliasNotFound { alias: alias.to_string() }),
        }
    }

    pub fn add_script(&mut self, alias: String, script: Script, force: bool) -> Result<(), PierError> {
        if !force && self.config.scripts.contains_key(&alias) {
            return Err(PierError::AliasAlreadyExists { alias });
        }
        self.config.scripts.insert(alias.clone(), script);
        self.config.write(&self.path)?;
        println!("Added {}", alias);
        Ok(())
    }

    pub fn remove_script(&mut self, alias: &str) -> Result<(), PierError> {
        let _ = self.fetch_script(alias)?;
        self.config.scripts.remove(alias);
        self.config.write(&self.path)?;
        println!("Removed {}", alias);
        Ok(())
    }

    pub fn copy_script(&mut self, from: &str, to: &str, force: bool) -> Result<(), PierError> {
        let s = self.fetch_script(from)?.clone();
        if !force && self.config.scripts.contains_key(to) {
            return Err(PierError::AliasAlreadyExists { alias: to.to_string() });
        }
        self.config.scripts.insert(to.to_string(), s);
        self.config.write(&self.path)?;
        println!("Copy from alias {} to new alias {}", from, to);
        Ok(())
    }

    pub fn move_script(&mut self, from: &str, to: &str, force: bool) -> Result<(), PierError> {
        let s = self.fetch_script(from)?.clone();
        if !force && self.config.scripts.contains_key(to) {
            return Err(PierError::AliasAlreadyExists { alias: to.to_string() });
        }
        self.config.scripts.remove(from);
        self.config.scripts.insert(to.to_string(), s);
        self.config.write(&self.path)?;
        println!("Move from alias {} to new alias {}", from, to);
        Ok(())
    }

    pub fn edit_script(&mut self, alias: &str) -> Result<(), PierError> {
        let current = self.fetch_script(alias)?.command.clone();
        let new_command = scrawl::with(&current).map_err(|e| PierError::EditorError { source: e })?;
        let new_command = strip_trailing_newline(&new_command).to_string();
        if let Some(script) = self.config.scripts.get_mut(alias) {
            script.command = new_command;
        }
        self.config.write(&self.path)?;
        println!("Edited {}", alias);
        Ok(())
    }

    pub fn run_script(&self, alias: &str, args: &[String], verbose: bool) -> Result<i32, PierError> {
        let script = self.fetch_script(alias)?;
        let interpreter = self.config.interpreter()?;
        if verbose {
            println!("Starting script \"{}\"", alias);
            println!("-------------------------");
        }
        let status = script::run(&interpreter, &script.command, alias, args)?;
        if verbose {
            println!("-------------------------");
            println!("Script complete");
        }
        Ok(status.code().unwrap_or(1))
    }

    pub fn list_scripts(&self, opts: &ListOpts) -> Result<(), PierError> {
        if self.config.scripts.is_empty() {
            return Err(PierError::NoScriptsExist);
        }
        if opts.list_aliases {
            for alias in self.list_aliases(&opts.tags) {
                println!("{}", alias);
            }
            return Ok(());
        }

        let cmd_width: Option<usize> = if opts.cmd_full {
            None
        } else if let Some(w) = opts.cmd_width {
            Some(w)
        } else {
            self.config.default.command_width
        };

        let mut table = Table::new();
        table.set_format(*COOL_FORMAT);
        table.set_titles(row!["Alias", "Tags", "Command", "Description"]);

        let rows = self.collect_rows(&opts.tags);
        for (alias, script) in rows {
            let tags = script
                .tags
                .as_ref()
                .map(|t| t.join(","))
                .unwrap_or_default();
            let cmd_str = match cmd_width {
                Some(w) => {
                    let s: String = script.command.chars().take(w).collect();
                    s
                }
                None => script.command.clone(),
            };
            let desc = script.description.clone().unwrap_or_default();
            table.add_row(row![alias, tags, cmd_str, desc]);
        }

        table.printstd();
        Ok(())
    }

    fn list_aliases(&self, tag_filter: &Option<Vec<String>>) -> Vec<String> {
        self.collect_rows(tag_filter)
            .into_iter()
            .map(|(a, _)| a)
            .collect()
    }

    fn collect_rows(&self, tag_filter: &Option<Vec<String>>) -> Vec<(String, Script)> {
        let mut out: Vec<(String, Script)> = Vec::new();
        match tag_filter {
            None => {
                for (a, s) in &self.config.scripts {
                    out.push((a.clone(), s.clone()));
                }
            }
            Some(filters) => {
                // Per probing: count of matches = output count; alphabetical script order
                for (a, s) in &self.config.scripts {
                    if let Some(tags) = &s.tags {
                        let matches = filters.iter().filter(|f| tags.contains(f)).count();
                        for _ in 0..matches {
                            out.push((a.clone(), s.clone()));
                        }
                    } else if filters.iter().any(|f| f.is_empty()) {
                        // empty tag filter matches a script with empty tag — only matches if tag is "" present
                    }
                }
            }
        }
        out
    }
}

fn strip_trailing_newline(s: &str) -> &str {
    s.strip_suffix("\r\n")
        .or_else(|| s.strip_suffix('\n'))
        .unwrap_or(s)
}

fn print_err(err: &PierError) {
    let _ = writeln!(std::io::stderr(), "error: {}", err);
}

pub fn run(cli: Cli) -> i32 {
    // config-init is the only command that doesn't read a config file
    if let Some(CliSubcommand::ConfigInit) = &cli.subcommand {
        let path = match resolve_init_path(cli.config.as_ref()) {
            Ok(p) => p,
            Err(e) => {
                print_err(&e);
                return 1;
            }
        };
        return match config::init(&path) {
            Ok(()) => {
                println!("Added hello-pier");
                0
            }
            Err(e) => {
                print_err(&e);
                1
            }
        };
    }

    let path = match defaults::resolve_config_path(cli.config.as_ref()) {
        Ok(p) => p,
        Err(e) => {
            print_err(&e);
            return 1;
        }
    };

    let mut pier = match Pier::from(path) {
        Ok(p) => p,
        Err(e) => {
            print_err(&e);
            return 1;
        }
    };

    let verbose = cli.verbose;
    let result: Result<i32, PierError> = match cli.subcommand {
        None => match cli.alias {
            Some(alias) => pier.run_script(&alias, &cli.args, verbose),
            None => unreachable!(),
        },
        Some(sub) => match sub {
            CliSubcommand::ConfigInit => unreachable!(),
            CliSubcommand::Add(a) => {
                let AddOpts { force, alias, description, tags, command } = a;
                let cmd = match command {
                    Some(c) => c,
                    None => {
                        let text = scrawl::new().map_err(|e| PierError::EditorError { source: e });
                        match text {
                            Ok(t) => strip_trailing_newline(&t).to_string(),
                            Err(e) => {
                                print_err(&e);
                                return 1;
                            }
                        }
                    }
                };
                let script = Script {
                    command: cmd,
                    description,
                    reference: None,
                    tags,
                };
                pier.add_script(alias, script, force).map(|_| 0)
            }
            CliSubcommand::Remove { alias } => pier.remove_script(&alias).map(|_| 0),
            CliSubcommand::Copy { from, to } => pier.copy_script(&from, &to, false).map(|_| 0),
            CliSubcommand::Move { force, from, to } => pier.move_script(&from, &to, force).map(|_| 0),
            CliSubcommand::Edit { alias } => pier.edit_script(&alias).map(|_| 0),
            CliSubcommand::Show { alias } => {
                let s = pier.fetch_script(&alias)?;
                println!("{}", s.command);
                Ok(0)
            }
            CliSubcommand::List(opts) => pier.list_scripts(&opts).map(|_| 0),
            CliSubcommand::Run { alias, args } => pier.run_script(&alias, &args, verbose),
        },
    };

    match result {
        Ok(code) => code,
        Err(e) => {
            print_err(&e);
            1
        }
    }
}

fn resolve_init_path(explicit: Option<&PathBuf>) -> Result<PathBuf, PierError> {
    if let Some(p) = explicit {
        return Ok(p.clone());
    }
    if let Ok(p) = std::env::var("PIER_CONFIG_PATH") {
