lazy_static! {
    pub static ref COOL_FORMAT: TableFormat = FormatBuilder::new()
        .column_separator('\u{22EE}')
        .borders('\u{22EE}')
        .separators(
            &[LinePosition::Top, LinePosition::Title, LinePosition::Bottom],
