use std::collections::BTreeMap;
use std::fs;
use std::path::Path;

use crate::error::PierError;
use crate::script::Script;

#[derive(Debug, Default, Serialize, Deserialize)]
pub struct Config {
    #[serde(default)]
    pub scripts: BTreeMap<String, Script>,
    #[serde(default)]
    pub default: ConfigDefaultOpts,
}

#[derive(Debug, Default, Serialize, Deserialize)]
pub struct ConfigDefaultOpts {
    pub command_width: Option<usize>,
    pub interpreter: Option<Vec<String>>,
}

impl Config {
    pub fn read(path: &Path) -> Result<Config, PierError> {
        let bytes = fs::read(path).map_err(|source| PierError::ConfigRead {
            source,
            path: path.to_path_buf(),
        })?;
        let s = String::from_utf8_lossy(&bytes).into_owned();
        let cfg: Config = toml::from_str(&s).map_err(|source| PierError::ConfigParse {
            source,
            path: path.to_path_buf(),
        })?;
        Ok(cfg)
    }

    pub fn write(&self, path: &Path) -> Result<(), PierError> {
        let s = toml::to_string(self).map_err(|source| PierError::ConfigSerialize { source })?;
        fs::write(path, s).map_err(|source| PierError::ConfigWrite {
            source,
            path: path.to_path_buf(),
        })?;
        Ok(())
    }

    pub fn interpreter(&self) -> Result<Vec<String>, PierError> {
        if let Some(i) = &self.default.interpreter {
            return Ok(i.clone());
        }
        let shell = match std::env::var("SHELL") {
            Ok(s) => s,
            Err(_) => String::from("/bin/sh"),
        };
        Ok(vec![shell, String::from("-c")])
    }
}

pub fn init(path: &Path) -> Result<(), PierError> {
    if path.exists() {
        return Err(PierError::ConfigInitFileExists {
            path: path.to_path_buf(),
        });
    }
    // Match exact bytes of reference output
    let content = "[scripts.hello-pier]\ncommand = 'echo Hello, Pier!'\ndescription = 'This is an example command.'\n\n[default]\n";
    if let Some(parent) = path.parent() {
        if !parent.as_os_str().is_empty() && !parent.exists() {
            fs::create_dir_all(parent).map_err(|source| PierError::FailedCreateDirectory { source })?;
        }
    }
    fs::write(path, content).map_err(|source| PierError::ConfigWrite {
        source,
        path: path.to_path_buf(),
    })?;
    Ok(())
}

