        if !parent.as_os_str().is_empty() && !parent.exists() {
            fs::create_dir_all(parent).map_err(|source| PierError::FailedCreateDirectory { source })?;
        }
    }
    fs::write(path, content).map_err(|source| PierError::ConfigWrite {
        source,
        path: path.to_path_buf(),
    })?;
    Ok(())
}

