pub fn run(
    interpreter: &[String],
    command: &str,
    alias: &str,
    args: &[String],
) -> Result<ExitStatus, PierError> {
    // Indexing interpreter[0] intentionally to mirror reference panic behavior
    // when interpreter is an empty array.
    let mut cmd = Command::new(&interpreter[0]);
    for a in &interpreter[1..] {
        cmd.arg(a);
    }
    cmd.arg(command);
    cmd.arg(alias);
    for a in args {
        cmd.arg(a);
    }
    cmd.stdin(Stdio::inherit());
    cmd.stdout(Stdio::inherit());
    cmd.stderr(Stdio::inherit());

    let status = cmd
        .status()
        .map_err(|source| PierError::CommandExec { source })?;
    Ok(status)
}

