use std::fmt;
use std::path::PathBuf;

#[derive(Debug)]
pub enum PierError {
    ConfigRead { source: std::io::Error, path: PathBuf },
    ConfigParse { source: toml::de::Error, path: PathBuf },
    ConfigSerialize { source: toml::ser::Error },
    ConfigWrite { source: std::io::Error, path: PathBuf },
    AliasNotFound { alias: String },
    AliasAlreadyExists { alias: String },
    NoScriptsExist,
    CommandExec { source: std::io::Error },
    NoConfigFile,
    ConfigInitFileExists { path: PathBuf },
    EditorError { source: scrawl::error::ScrawlError },
    FailedCreateDirectory { source: std::io::Error },
}

impl fmt::Display for PierError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            // Trailing space before newline mirrors reference behavior
            PierError::ConfigRead { source, path } => {
                write!(f, "Unable to read config from file {}: {} ", path.display(), source)
            }
            PierError::ConfigParse { source, path } => {
                write!(f, "Unable to parse toml config from file {}: {}", path.display(), source)
            }
            PierError::ConfigSerialize { source } => {
                write!(f, "Unable to serialize config: {}. Probably a bug in the code.", source)
            }
            PierError::ConfigWrite { source, path } => {
                write!(f, "Unable to write config to {}: {}", path.display(), source)
            }
            PierError::AliasNotFound { alias } => {
                write!(f, "AliasNotFound: No script found by alias {}", alias)
            }
            PierError::AliasAlreadyExists { alias } => {
                write!(f, "AliasAlreadyExists:  {}", alias)
            }
            PierError::NoScriptsExist => {
                write!(f, "No scripts exist. Would you like to add a new script?")
            }
            PierError::CommandExec { source } => {
                write!(f, "Command execution failed with: {}", source)
            }
            PierError::NoConfigFile => {
                write!(f, "No default config file found. See help for more info.")
            }
            PierError::ConfigInitFileExists { path } => {
                write!(f, "Cannot initialize config at {}, file already exists.", path.display())
            }
            PierError::EditorError { source } => {
                write!(f, "EditorError: Failed when trying to get input from editor {}", source)
            }
            PierError::FailedCreateDirectory { source } => {
                write!(f, "Failed to create directory. {}", source)
            }
        }
    }
}

