use std::path::PathBuf;

use crate::error::PierError;

pub fn resolve_config_path(explicit: Option<&PathBuf>) -> Result<PathBuf, PierError> {
    if let Some(p) = explicit {
        return Ok(p.clone());
    }
    if let Ok(p) = std::env::var("PIER_CONFIG_PATH") {
        return Ok(PathBuf::from(p));
    }
    // ./pier.toml
    let cur = PathBuf::from("pier.toml");
    if cur.exists() {
        return Ok(cur);
    }
    let xdg = xdg_config_home();
    if let Some(xdg) = xdg {
        let candidates = [
            xdg.join("pier/config.toml"),
            xdg.join("pier/config"),
            xdg.join("pier.toml"),
        ];
        for c in &candidates {
            if c.exists() {
                return Ok(c.clone());
            }
        }
    }
    if let Some(home) = home_dir() {
        for f in ["/.pier.toml", "/.pier"] {
            let mut p = home.clone();
            p.push(&f[1..]);
            if p.exists() {
                return Ok(p);
            }
        }
    }
    Err(PierError::NoConfigFile)
}

pub fn fallback_path() -> Result<PathBuf, PierError> {
    if let Some(xdg) = xdg_config_home() {
        return Ok(xdg.join("pier/config.toml"));
    }
    if let Some(home) = home_dir() {
        return Ok(home.join(".pier.toml"));
    }
    Err(PierError::NoConfigFile)
}

fn xdg_config_home() -> Option<PathBuf> {
    if let Ok(v) = std::env::var("XDG_CONFIG_HOME") {
        if !v.is_empty() {
            return Some(PathBuf::from(v));
        }
    }
    if let Some(h) = home_dir() {
        return Some(h.join(".config"));
    }
    None
}

fn home_dir() -> Option<PathBuf> {
    if let Ok(v) = std::env::var("HOME") {
        if !v.is_empty() {
            return Some(PathBuf::from(v));
        }
    }
    None
}

